clear;
close all;

fs = 600e6;
c = 3e8;
N = 1; % 脉冲数

fc = 4e9; % 载频  
% f0 = 1e9; % 基带
f0=0;
dertaf = 0.5e6; % 子载波频率间隔
n = 400; % 子载波个数
Bx = n*dertaf; % 总带宽
Tp = 25e-6;

%% 发射信号
% t = 0:1/fs:Tp-1/fs;
% t = -Tp/2:1/fs:Tp/2-1/fs;
% x = zeros(1,Tp*fs);
% win = ones(1,Tp*fs);
% for i = 1:n
%     x0 = win.*exp(1j*2*pi*(f0+(i-1)*dertaf)*t);
% %     figure, plot(abs(x0));
%     x = x+x0;
% %     figure, plot(abs(x));
% end
% % figure, plot(t, abs(x)); title('发射脉冲时域')
% % X = fftshift(fft(x));
% % f = fs*(-Tp*fs/2:Tp*fs/2-1)/(Tp*fs);
% % figure, plot(f,abs(X)); title('发射脉冲频域')

%% 回波信号
% rtar = 5001.21;
% vtar = 20;
% tobject = 2*rtar/c;
% 
% wavecenter = 5000;
% wavewidth = 3*Tp;
% nrn = floor(wavewidth*fs);
% tstart = 2*wavecenter/c-nrn/2/fs;
% tend = 2*wavecenter/c+(nrn/2-1)/fs;
% tnrn = (tstart:1/fs:tend);
% 
% winecho = (tnrn-tobject)>=(-Tp/2) & (tnrn-tobject)<=(Tp/2);
% echo = zeros(1,nrn);
% for i = 1:n
%     echo = echo + winecho.*exp(1j*2*pi*(f0+(i-1)*dertaf)*(tnrn-tobject));
% end
% Echo = fftshift(fft(echo));
% fnrn = fs*(-nrn/2:nrn/2-1)/nrn;
% % figure, plot(abs(winecho));
% % figure, plot(tnrn,abs(echo)); title('回波信号时域')
% % figure, plot(fnrn,abs(Echo)); title('回波信号频域')


%% optimization solution
ts=1/fs;
total_sample_num=Tp*fs;
V=zeros(total_sample_num,n);
for i=0:1:n-1
    for samle_num=0:1:total_sample_num-1
         V(samle_num+1,i+1)=exp(1j*2*pi*(f0+i*dertaf)*(samle_num)*ts);        %求V
    end
end

V_tilde=(fft(V));    %V的离散傅里叶变换
band_stop=[2000,2374];    % 阻带
temp0=V_tilde;
temp1=V_tilde;
temp1(band_stop(1):band_stop(2),:)=0;
temp0(1:band_stop(1)-1,:)=0;
temp0(band_stop(2)+1:total_sample_num,:)=0;
V0_tilde=temp0;     %设置阻带频率集
V1_tilde=temp1;     %设置通带频率集
waveform_x=solution(V0_tilde,V1_tilde,V_tilde,V,n,total_sample_num,band_stop);
function waveform_x_bar=solution(V0_tilde,V1_tilde,V_tilde,V,n,total_sample_num,band_stop)
%% 参数设置
Iter=2000;
delta1=0.1;
delta2=0.1;
delta3=0.1;  %公差参数设置
r=2; %波纹控制项
rho=1;
% rho_max=1e6;
lambda1=rand(2*total_sample_num,1);
U=10;
L=8;
% a=rand(n,1)+1i*rand(n,1);
a=zeros(n,1);       
waveform_x=V*a;
% a_bar=[real(a)',imag(a)']';
% waveform_x=zeros(1,total_sample_num)';   %初始化
waveform_x_bar=[real(waveform_x)',imag(waveform_x)']';
% Re_V=real(V_tilde);
% Im_V=imag(V_tilde);
R=conj(V0_tilde).'*V0_tilde;
R_bar=[real(R),-imag(R);imag(R),real(R) ];
V_bar=[real(V),-imag(V);imag(V), real(V)];
Vp=cat(1,V1_tilde(1:band_stop(1)-1,:),V1_tilde(band_stop(2)+1:total_sample_num,:));% Vp是vp的集合   每一行代表一个vp
row_Vp=size(Vp,1);
lambda2=rand(2,row_Vp);    
Vp_bar=zeros(2*row_Vp,2*n);
for i=1:1:row_Vp
    Vp_bar(2*i-1:2*i,:)=[real(Vp(i,:)),-imag(Vp(i,:));imag(Vp(i,:)),real(Vp(i,:))];
end
sum_Vp_bar=zeros(2*n,2*n);
for i=1:1:row_Vp
    sum_Vp_bar=sum_Vp_bar+rho/2*Vp_bar(2*i-1:2*i,:)'* Vp_bar(2*i-1:2*i,:);
end
Fp=Vp*a;       % fp的集合  FP的每一个元素代表fp
Fp_bar=[real(Fp)';imag(Fp)'];    
R1=R_bar+1/2*rho*V_bar'*V_bar+sum_Vp_bar;

%% 迭代
tic
for iter=1:1:Iter
    % 对a_bar进行更新
    fp_lambda2=zeros(1,2*n);
    fp_vp=zeros(1,2*n);
    for i=1:1:row_Vp
          fp_lambda2=fp_lambda2+lambda2(:,i)'*Fp_bar(:,i);
          fp_vp=fp_vp+rho*Fp_bar(:,i)'*  Vp_bar(2*i-1:2*i,:);
    end
      d1=-lambda1'*V_bar-rho*waveform_x_bar'*V_bar- fp_lambda2-fp_vp;
      a_bar=-(R1'+R1)\d1';
%        a_bar=-(R1)\d1';
      % 对x_bar进行更新
      d2=lambda1-rho*V_bar*a_bar;
      for k=1:1:row_Vp
          temp_part_d2=[d2(k);d2(k+row_Vp)];
          waveform_x_bar(k)= d2(k)/norm(temp_part_d2,2);
          waveform_x_bar(k+row_Vp)=d2(k+row_Vp)/norm(temp_part_d2,2);
      end
      % 对fp_bar进行更新
      for p=1:1:row_Vp
         fp_b(:,p)=Vp_bar(2*p-1:2*p,:)* a_bar-1/rho*lambda2(:,p);
%          abs_fp(1,p)=Fp_bar(1,p)^2+Fp_bar(2,p)^2;
      end
      temp_b1=sqrt( (U+L)/2+r );
      temp_b2=sqrt( (U+L)/2-r );
%       if (max(abs_fp)+min(abs_fp))/2-r <= 0
%           temp_b2=0;
%       end
      for  p=1:1:row_Vp
              temp_norm=norm( fp_b(:,p),2);
           if(temp_norm>=temp_b1)
               Fp_bar(:,p)= temp_b1/temp_norm*fp_b(:,p);
           else if (temp_norm<=temp_b2)
                    Fp_bar(:,p)= temp_b2/temp_norm*fp_b(:,p);

           else if (temp_b2<temp_norm && temp_norm < temp_b1)
                         Fp_bar(:,p)= fp_b(:,p);
               end

               end
           end 
      end
      % 更新lambda1与lambda2
        lambda1= lambda1+rho*(waveform_x_bar-V_bar*a_bar);
        temp_vp_a=zeros(2,row_Vp);
        for p=1:1:row_Vp
            temp_vp_a(:,p)=Fp_bar(:,p)-Vp_bar(2*p-1:2*p,:)*a_bar;
            lambda2(:,p)=lambda2(:,p)+rho* temp_vp_a(:,p);
        end
%          rho= min(rho_max,1.5*rho);
     % 判断迭代停止
     stop_condition1=norm(waveform_x_bar-V_bar*a_bar,2);
     stop_condition2=norm( temp_vp_a,2);
     if stop_condition1<delta1&&stop_condition2<delta2
         break;
     end

 end
toc
end
这段代码什么含义

在MATLAB中使用`fmincon`函数求解具有400个变量的优化问题是完全可行的。`fmincon`函数是MATLAB中用于求解有约束的非线性优化问题的函数，可以处理包括等式约束、不等式约束以及边界约束在内的多种情况。

下面是一个简单的示例，演示如何在MATLAB中使用`fmincon`函数求解一个具有400个变量的优化问题：

假设我们要最小化函数 `fun(x) = x(1)^2 + x(2)^2 + ... + x(400)^2`，其中x是一个包含400个变量的向量。

```matlab
% 定义函数
fun = @(x) sum(x.^2);

% 初始值
x0 = zeros(400, 1);

% 定义约束
A = [];
b = [];
Aeq = [];
beq = [];
lb = []; % lower bound
ub = []; % upper bound

% 调用fmincon进行优化
[x, fval] = fmincon(fun, x0, A, b, Aeq, beq, lb, ub);

disp(['最小值为: ', num2str(fval)]);
disp('最优变量为:');
disp(x);
```

在这个示例中，我们定义了一个简单的目标函数，然后设置了初始值、约束条件以及边界条件，并调用`fmincon`函数进行优化。您可以根据您的具体问题定义相应的目标函数、约束条件和边界条件，然后使用`fmincon`函数进行求解。

可以通过以下代码实现将一个（1，400）的向量的50-65元素置为零：

```matlab
% 生成一个包含400个随机值的向量
v = rand(1, 400);

% 将50到65元素置零
v(50:65) = 0;

% 显示结果
disp(v);
```

在这段代码中，首先生成一个包含400个随机值的向量 `v`，然后将第50到第65个元素置为零，最后显示结果。您可以在实际应用中将`rand(1, 400)`替换为您自己的向量。
